import base64,gzip,os,subprocess,sys
FILES={
  'index.html': '',
  'assets/app.js': '',
  'assets/style.css': '',
  'scripts/update_data.py': '',
  'manifest.webmanifest': '',
  'sw.js': '',
}

root = os.path.dirname(os.path.abspath(__file__))
for path, data in FILES.items():
    full = os.path.join(root, path)
    os.makedirs(os.path.dirname(full), exist_ok=True)
    content = gzip.decompress(base64.b64decode(data))
    with open(full, 'wb') as f:
        f.write(content)
    print(f"  ✅ {path}")

print("\nDateien geschrieben. Jetzt pushen:")
try:
    subprocess.run(["git","add","."], cwd=root, check=True)
    subprocess.run(["git","commit","-m","Cockpit + Alerts + Premarket + PWA"], cwd=root, check=True)
    subprocess.run(["git","push"], cwd=root, check=True)
    print("🚀 Gepusht! Cloudflare deployt in ~1 Min.")
except subprocess.CalledProcessError as e:
    print(f"Git-Fehler: {e}\nBitte manuell ausführen:\n  cd {root}\n  git add . && git commit -m \"Deploy\" && git push")
